const requestedEntrySlug = input?.entry_slug || 'city-garden';
const collection = {
  name: 'Field Notes',
  slug: 'field-notes'
};
const entry = {
  title: requestedEntrySlug === 'city-garden' ? 'City Garden' : requestedEntrySlug,
  slug: requestedEntrySlug,
  summary: 'A compact example of one generated static content page.',
  body: `A small archive can still feel deliberate.\n\nThis example shows how one payload becomes one persisted HTML artifact.`
};
return {
  collection,
  entry,
  related_labels: [
    { slug: 'example', label: 'Example' },
    { slug: 'static', label: 'Static' }
  ],
  generated_at: new Date().toISOString()
};
